var e=JSON.parse(`[{"id":"L2_1","type":"dialog","speaker":"MINA_FENRIR_CHIEF_NULL","text":{"KOREA":"불합격이야. 이제 돌아가.","JPN":"不合格。もう帰って。","ENG":"You didn't pass. Go home.","TWN":"淘汰，你回去吧。"},"stage":{"bg":"TRAINING","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MINA_FENRIR_CHIEF_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L3_1","type":"dialog","speaker":"INTERN_FENRIR_NULL_NULL","text":{"KOREA":"에엣?! 아직 준비해 온 춤도 노래도 요리도 제대로 못 보여드렸는데요!","JPN":"ええっ！？　まだ準備してきたダンスも、歌も、料理もちゃんとお見せできていません！","ENG":"What?! But I still haven't shown you my dance moves, my singing skills, or my cooking!","TWN":"這麼快！？我有準備要唱歌、跳舞跟做菜欸！都還沒表演呢！"},"stage":{"bg":"TRAINING","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"INTERN_FENRIR_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L4_1","type":"dialog","speaker":"MINA_FENRIR_CHIEF_NULL","text":{"KOREA":"그런 걸 왜 준비해 온 거야…?","JPN":"なんでそんなの準備してきたの……？","ENG":"Why did you even prepare all of that...?","TWN":"準備這種東西要幹嘛…？"},"stage":{"bg":"TRAINING","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MINA_FENRIR_CHIEF_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L5_1","type":"dialog","speaker":"MINA_FENRIR_CHIEF_NULL","text":{"KOREA":"이미 결정난 일이야. 부모님 있는 데로 돌아가.","JPN":"もう決まったことだよ。ご両親のいるところに帰りな。","ENG":"The decision's been made. Go back to your family.","TWN":"事已成定局，你回去找你爸媽吧。"},"stage":{"bg":"TRAINING","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MINA_FENRIR_CHIEF_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L8_1","type":"dialog","speaker":"INTERN_FENRIR_NULL_NULL","text":{"KOREA":"그러지 말고 한 번만 더 고민해 주세요! 전 펜릴 소대에 꼭 들어가고 싶어요!","JPN":"そうおっしゃらず、もう一度だけ考えてみてください！　私、絶対フェンリル小隊に入りたいんです！","ENG":"Please, could you at least reconsider? I really want to join Fenrir Squad!","TWN":"不要這樣啦，拜託你們再考慮一下！我一定要進芬里爾小隊！"},"stage":{"bg":"TRAINING","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"INTERN_FENRIR_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L9_1","type":"dialog","speaker":"INTERN_FENRIR_NULL_NULL","text":{"KOREA":"분명 무슨 방법이 있을 거예요! 그렇죠?","JPN":"きっと何か方法があるはずです！　ね？","ENG":"There has to be some way, right?","TWN":"一定有什麼辦法的！有吧？"},"stage":{"bg":"TRAINING","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"INTERN_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L10_1","type":"dialog","speaker":"INTERN_FENRIR_NULL_NULL","text":{"KOREA":"가르쳐 주시면 안 돼요? 네?","JPN":"教えてもらえませんか？　ね？","ENG":"Can't you tell me? Please?","TWN":"可以告訴我嗎？拜託？"},"stage":{"bg":"TRAINING","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"INTERN_FENRIR_NULL_NULL","face":"UNIT_LAUGH"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_04"},{"id":"L11_1","type":"dialog","speaker":null,"text":{"KOREA":"이, 일단 좀 떨어져서 얘기하게나.","JPN":"い、いったん少し離れて話してくれたまえ。","ENG":"H-how about we take a step back and then talk?","TWN":"那個，可以先保持一下安全社交距離嗎？"},"stage":{"bg":"TRAINING","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"INTERN_FENRIR_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L12_1","type":"dialog","speaker":"MINA_FENRIR_CHIEF_NULL","text":{"KOREA":"하아. 포기할 줄을 모르네.","JPN":"はあ。諦めが悪いんだね。","ENG":"*Sigh* She's not going to give up, is she?","TWN":"哀，有夠堅持的。"},"stage":{"bg":"TRAINING","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MINA_FENRIR_CHIEF_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"MINA_FENRIR_CHIEF_NULL","text":{"KOREA":"그럼 어디 3종 침식체라도 잡아 와.","JPN":"じゃあ、どこかで第3種侵食体でも捕まえてきて。","ENG":"Then go defeat a Category 3 C.O.","TWN":"那你抓個3類侵蝕體來看看。"},"stage":{"bg":"TRAINING","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MINA_FENRIR_CHIEF_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"INTERN_FENRIR_NULL_NULL","text":{"KOREA":"3종 침식체를요?","JPN":"第3種侵食体をですか？","ENG":"A Category 3 C.O.?","TWN":"3類侵蝕體嗎？"},"stage":{"bg":"TRAINING","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"INTERN_FENRIR_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"MINA_FENRIR_CHIEF_NULL","text":{"KOREA":"그래. 어차피 살면서 한 번 마주치기도 힘들겠지만.","JPN":"そう。どうせ一生に一度出くわすかどうかだろうけど。","ENG":"Yes. Even coming across one will be a once-in-a-lifetime experience.","TWN":"沒錯，不過3類侵蝕體也不是你想遇就遇得到的。"},"stage":{"bg":"TRAINING","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MINA_FENRIR_CHIEF_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"INTERN_FENRIR_NULL_NULL","text":{"KOREA":"고마워요, 유미나 님!","JPN":"ありがとうございます、ミナ様！","ENG":"Thank you, Ms. Mina!","TWN":"謝謝劉米娜小姐！"},"stage":{"bg":"TRAINING","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"INTERN_FENRIR_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"INTERN_FENRIR_NULL_NULL","text":{"KOREA":"도전! 지금부터 3종 침식체를 잡으러 출발!","JPN":"挑戦！　今から第3種侵食体を捕まえに出発！","ENG":"Challenge accepted! Let's go get myself a Category 3 C.O.!","TWN":"挑戰！我現在就去抓3類侵蝕體！"},"stage":{"bg":"TRAINING","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"INTERN_FENRIR_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"MINA_FENRIR_CHIEF_NULL","text":{"KOREA":"……뭐야, 쟤? 태스크포스 지원자라면서?","JPN":"……何？　あいつ。タスクフォースの志願者じゃなかったの？","ENG":"...What's up with her? Didn't you say she was a TASKFORCE applicant?","TWN":"……她有什麼問題？這樣還要應徵特遣勢力？"},"stage":{"bg":"TRAINING","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MINA_FENRIR_CHIEF_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"LEESOOYEON_COFFIN_NULL_NULL","text":{"KOREA":"가끔은 저렇게 세상 물정 모르는 아이들도 있어요.","JPN":"たまにあんな世間知らずな子もいるんです。","ENG":"Sometimes, there are kids who are too naive to understand the world.","TWN":"世界上確實有些人跟她一樣不知道天高地厚。"},"stage":{"bg":"TRAINING","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":"LEESOOYEON_COFFIN_NULL_NULL","text":{"KOREA":"입사할 때의 미나 양처럼 말이죠.","JPN":"入社したときのミナさんのように。","ENG":"Just like you when you first joined us, Mina.","TWN":"就像剛進公司時的你一樣。"},"stage":{"bg":"TRAINING","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"MINA_FENRIR_CHIEF_NULL","text":{"KOREA":"그건…….","JPN":"それは……","ENG":"But that’s...","TWN":"那是……"},"stage":{"bg":"TRAINING","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MINA_FENRIR_CHIEF_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L23_1","type":"dialog","speaker":"LEESOOYEON_COFFIN_NULL_NULL","text":{"KOREA":"오늘 면접은 여기서 끝이겠군요. 오후 지원자들에게도 소문이 퍼졌을 테니까요.","JPN":"今日の面接はこれで終了ですね。午後の志願者たちにもウワサは広まっているはずですから。","ENG":"That will be all for today's interviews. I bet rumors have already spread to the second-half applicants.","TWN":"今天的面試應該差不多就這樣，我想下午消息就會傳到應徵者的耳裡。"},"stage":{"bg":"TRAINING","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L24_1","type":"dialog","speaker":"LEESOOYEON_COFFIN_NULL_NULL","text":{"KOREA":"남은 시간 동안 사장님과 말씀 나누도록 하세요.","JPN":"残り時間は社長とお話でもしてください。","ENG":"For the remaining time, you can have a talk with Boss.","TWN":"接下來的時間，你就跟老闆好好談談吧。"},"stage":{"bg":"TRAINING","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L25_1","type":"dialog","speaker":"LEESOOYEON_COFFIN_NULL_NULL","text":{"KOREA":"지금 미나 양에게 필요한 건 면접이 아니라 면담 같으니까요.","JPN":"今のミナさんに必要なのは、面接ではなくて面談のようですから。","ENG":"I think what you need now, Mina, is a counseling  than an interview.","TWN":"現在你需要的不是面試，而是約談。"},"stage":{"bg":"TRAINING","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L27_1","type":"dialog","speaker":"LEESOOYEON_COFFIN_NULL_NULL","text":{"KOREA":"잠시 자리를 비워 줘야겠군요. 가죠. 하나 씨.","JPN":"しばらく席を外します。行きましょう。ナカシマさん。","ENG":"We will leave the two of you alone. Let's go, Miss Kim.","TWN":"我要失陪一下。荷娜，我們走吧。"},"stage":{"bg":"TRAINING","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"KIMHANA_COFFIN_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L29_1","type":"dialog","speaker":"KIMHANA_COFFIN_NULL_NULL","text":{"KOREA":"아, 네. 그럼 이만 실례하겠습니다.","JPN":"あ、はい。それでは、失礼します。","ENG":"Oh, okay. Excuse us.","TWN":"喔，好，那就先失陪了。"},"stage":{"bg":"TRAINING","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KIMHANA_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L32_1","type":"dialog","speaker":null,"text":{"KOREA":"묻고 싶은 게 많은 표정이군.","JPN":"聞きたいことがたくさんあるという顔だな。","ENG":"You look like you have a lot of questions for me.","TWN":"你臉上寫著滿滿的問號呢。"},"stage":{"bg":"TRAINING","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MINA_FENRIR_CHIEF_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L33_1","type":"dialog","speaker":"MINA_FENRIR_CHIEF_NULL","text":{"KOREA":"……당연하지.","JPN":"……当たり前だよ。","ENG":"...Of course, I do.","TWN":"……那當然。"},"stage":{"bg":"TRAINING","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MINA_FENRIR_CHIEF_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L34_1","type":"dialog","speaker":"MINA_FENRIR_CHIEF_NULL","text":{"KOREA":"사장님에 대해선 그 날 들었던 대로라고 믿을게.","JPN":"社長については、あの日聞いたとおりだと信じる。","ENG":"But I'll believe what I heard about you that day is true.","TWN":"我相信老闆的事就跟那天我聽到的一樣。"},"stage":{"bg":"TRAINING","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MINA_FENRIR_CHIEF_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L35_1","type":"dialog","speaker":"MINA_FENRIR_CHIEF_NULL","text":{"KOREA":"병실에 누워 있던 언니가 사실은 마왕이라는 것도.","JPN":"病室に寝ていた姉さんが、実は魔王だってことも。","ENG":"That my sister is actually a Demon Lord.","TWN":"還有躺在醫院裡的姊姊其實是魔王。"},"stage":{"bg":"TRAINING","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MINA_FENRIR_CHIEF_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L36_1","type":"dialog","speaker":"MINA_FENRIR_CHIEF_NULL","text":{"KOREA":"사장님이 소대장과 함께 언니를 막기 위해 여러 세상을 떠돌아 다녔다는 것도.","JPN":"社長が小隊長と一緒に姉さんを止めるためにいろんな世界を回ってたってことも。","ENG":"That you and Commander hop between worlds together to stop my sister.","TWN":"以及老闆和小隊長為了阻止姊姊，在許多世界奔走。"},"stage":{"bg":"TRAINING","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MINA_FENRIR_CHIEF_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L37_1","type":"dialog","speaker":"MINA_FENRIR_CHIEF_NULL","text":{"KOREA":"그리고…….","JPN":"それに……","ENG":"And...","TWN":"還有……"},"stage":{"bg":"TRAINING","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MINA_FENRIR_CHIEF_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L39_1","type":"dialog","speaker":null,"text":{"KOREA":"<color=#ffd34c>전술 업데이트 – 명계검</color>","JPN":"<color=#ffd34c>戦術アップデート – 冥府剣</color>","ENG":"<color=#ffd34c>Tactical Update – Nether Blade</color>","TWN":"<color=#ffd34c>戰術升級 – 冥神劍</color>"},"stage":{"bg":"black","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}},"sfx":"FX_COMBAT_ALL_MAGIC_SPELL_61"},{"id":"L40_1","type":"dialog","speaker":null,"text":{"KOREA":"<color=#ffd34c>전술 업데이트 – 엘리시움 피오레</color>","JPN":"<color=#ffd34c>戦術アップデート – エリシウムフィオーレ</color>","ENG":"<color=#ffd34c>Tactical Update – Elysium Fiore</color>","TWN":"<color=#ffd34c>戰術升級 – 極樂之花</color>"},"stage":{"bg":"black","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}},"sfx":"FX_COMBAT_ALL_MAGIC_SPELL_61"},{"id":"L41_1","type":"dialog","speaker":null,"text":{"KOREA":"<color=#ffd34c>전술 업데이트 – 성간연합 군용 총검술</color>","JPN":"<color=#ffd34c>戦術アップデート – 星間連合軍用銃剣術</color>","ENG":"<color=#ffd34c>Tactical Update – Interstellar Alliance Bayonet</color>","TWN":"<color=#ffd34c>戰術升級 – 星際聯合軍用刺刀術</color>"},"stage":{"bg":"black","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}},"sfx":"FX_COMBAT_ALL_MAGIC_SPELL_61"},{"id":"L42_1","type":"dialog","speaker":null,"text":{"KOREA":"<color=#ffd34c>전술 업데이트 – 금술 백야천주살</color>","JPN":"<color=#ffd34c>戦術アップデート – 禁術・百夜天呪殺</color>","ENG":"<color=#ffd34c>Tactical Update – Forbidden: Night of Curses</color>","TWN":"<color=#ffd34c>戰術升級 – 禁術–白夜千誅刃</color>"},"stage":{"bg":"black","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}},"sfx":"FX_COMBAT_ALL_MAGIC_SPELL_61"},{"id":"L44_1","type":"dialog","speaker":"MINA_FENRIR_CHIEF_NULL","text":{"KOREA":"그 세상에 있던 <color=#ffd34c>나</color>와 함께 싸웠다는 것도.","JPN":"あの世界にいた<color=#ffd34c>私</color>と一緒に戦ったってことも。","ENG":"That You fought with <color=#ffd34c>me</color> in that world.","TWN":"和那個世界的<color=#ffd34c>我</color>一起作戰，"},"stage":{"bg":"OFFICE_NORMAL","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MINA_FENRIR_CHIEF_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L45_1","type":"dialog","speaker":"MINA_FENRIR_CHIEF_NULL","text":{"KOREA":"하지만 그것만으로는 안심할 수가 없어.","JPN":"でも、それだけでは安心できないの。","ENG":"However, that doesn't reassure me.","TWN":"但光是這樣我還是無法安心。"},"stage":{"bg":"OFFICE_NORMAL","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MINA_FENRIR_CHIEF_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L46_1","type":"dialog","speaker":"MINA_FENRIR_CHIEF_NULL","text":{"KOREA":"내가 겪었던 일들이 전부….","JPN":"私が経験したことが全部……","ENG":"Everything that I've experienced...","TWN":"若是我所經歷的一切…"},"stage":{"bg":"OFFICE_NORMAL","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MINA_FENRIR_CHIEF_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L1_1","type":"dialog","speaker":"MINA_FENRIR_CHIEF_NULL","text":{"KOREA":"처음부터, 사장님이랑 언니 손바닥 위에서 놀아난 거라면?","JPN":"最初から社長と姉さんの手の上で踊らされていたんだとしたら？","ENG":"What if I was just being played by you and my sister?","TWN":"打從一開始，就被老闆和姊姊玩弄於股掌之間？"},"stage":{"bg":"OFFICE_NORMAL","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MINA_FENRIR_CHIEF_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L2_1","type":"dialog","speaker":"MINA_FENRIR_CHIEF_NULL","text":{"KOREA":"내가 하려고 했던 모든 게…. 그냥 체스판 위에서 시키는 대로 움직였던 거라면?","JPN":"私がしようとした全てが……ただチェス盤の上で指示されるがままに動いてただけなら？","ENG":"That everything I tried to do... was just me being moved around like a chess pawn?","TWN":"若是我想做的所有事…其實都只是照著你們的意思去做，我就像是棋盤上的棋子？"},"stage":{"bg":"OFFICE_NORMAL","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MINA_FENRIR_CHIEF_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L3_1","type":"dialog","speaker":null,"text":{"KOREA":"모든 것이 계획의 일환은 아니라네.","JPN":"全てが計画の一環ではない。","ENG":"Not everything is part of the plan.","TWN":"這一切並不是計劃裡的一環。"},"stage":{"bg":"OFFICE_NORMAL","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MINA_FENRIR_CHIEF_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L4_1","type":"dialog","speaker":"MINA_FENRIR_CHIEF_NULL","text":{"KOREA":"그건 자네의 판단에 달린 문제일세.","JPN":"それは君の判断次第さ。","ENG":"I believe that is for you to decide.","TWN":"這要取決於你的判斷。"},"stage":{"bg":"OFFICE_NORMAL","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MINA_FENRIR_CHIEF_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"MINA_FENRIR_CHIEF_NULL","text":{"KOREA":"……그렇게라도 말해 줘서 고마워.","JPN":"……そう言ってくれてありがとう。","ENG":"...Thanks for addressing that.","TWN":"……謝謝老闆這麼說。"},"stage":{"bg":"OFFICE_NORMAL","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MINA_FENRIR_CHIEF_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"MINA_FENRIR_CHIEF_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"OFFICE_NORMAL","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MINA_FENRIR_CHIEF_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L8_1","type":"dialog","speaker":"MINA_FENRIR_CHIEF_NULL","text":{"KOREA":"미안해, 사장님. 조금만 더 생각할 시간을 줘.","JPN":"ごめん、社長。もう少し考える時間をもらってもいいかな。","ENG":"I'm sorry, Boss. Just give me some time to think about it.","TWN":"對不起老闆，我需要再多一點思考的時間。"},"stage":{"bg":"OFFICE_NORMAL","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MINA_FENRIR_CHIEF_NULL","face":"UNIT_DESPAIR"},"R":null}}}]`);export{e as default};